#pragma once
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>

// Kernel launch configuration for A800
#define RMSNORM_H1536_BLOCK_SIZE 256
#define RMSNORM_H1536_HIDDEN_SIZE 1536

/**
 * RMSNorm kernel for hidden_size=1536 optimized for A800
 * 
 * @param hidden_states Input tensor [batch_size, 1536] in bfloat16
 * @param weight Weight tensor [1536] in bfloat16
 * @param output Output tensor [batch_size, 1536] in bfloat16
 * @param batch_size Number of batch elements
 * @param hidden_size Must be 1536
 * @param stream CUDA stream for async execution
 */
extern "C" void rmsnorm_h1536_kernel_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    cudaStream_t stream
);

/**
 * Device kernel for RMSNorm computation
 */
__global__ void rmsnorm_h1536_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size
);

#include "kernel.h"
#include <cmath>

// A800 optimized RMSNorm kernel for hidden_size=1536
__global__ void rmsnorm_h1536_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size
) {
    // Each block processes one batch element
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int tid = threadIdx.x;
    int num_threads = blockDim.x;

    // Shared memory for weight (1536 * 2 bytes = 3KB, well within A800 shared memory limits)
    extern __shared__ __nv_bfloat16 shared_weight[];

    // Load weight into shared memory (one-time per block)
    if (tid < hidden_size) {
        shared_weight[tid] = weight[tid];
    }
    __syncthreads();

    // Compute sum of squares for RMS calculation
    // Each thread processes multiple hidden dimensions
    float sum_sq = 0.0f;
    const float* hidden_ptr = reinterpret_cast<const float*>(hidden_states + batch_idx * hidden_size);

    // Unrolled loop for better performance on A800
    for (int i = tid; i < hidden_size; i += num_threads) {
        float x = __bfloat162float(hidden_states[batch_idx * hidden_size + i]);
        sum_sq += x * x;
    }

    // Parallel reduction for sum_sq across threads in block
    __shared__ float sum_sq_shared[256];
    sum_sq_shared[tid] = sum_sq;
    __syncthreads();

    // Tree-based reduction for better performance on A800
    for (int stride = num_threads / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            sum_sq_shared[tid] += sum_sq_shared[tid + stride];
        }
        __syncthreads();
    }

    // Compute RMS and inverse RMS
    float mean_sq = sum_sq_shared[0] / static_cast<float>(hidden_size);
    float rms = sqrtf(mean_sq + 1e-6f);
    float inv_rms = 1.0f / rms;

    // Normalize and apply weight
    for (int i = tid; i < hidden_size; i += num_threads) {
        float x = __bfloat162float(hidden_states[batch_idx * hidden_size + i]);
        float w = __bfloat162float(shared_weight[i]);
        float y = x * inv_rms * w;
        output[batch_idx * hidden_size + i] = __float2bfloat16(y);
    }
}

extern "C" void rmsnorm_h1536_kernel_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    cudaStream_t stream
) {
    // Validate hidden_size
    if (hidden_size != RMSNORM_H1536_HIDDEN_SIZE) {
        return;
    }

    // Configure kernel launch parameters for A800
    const int block_size = RMSNORM_H1536_BLOCK_SIZE;
    const int grid_size = batch_size;

    // Shared memory size for weight (1536 * 2 bytes = 3072 bytes)
    const int shared_mem_size = hidden_size * sizeof(__nv_bfloat16);

    // Launch kernel
    rmsnorm_h1536_kernel<<<grid_size, block_size, shared_mem_size, stream>>>(
        hidden_states,
        weight,
        output,
        batch_size,
        hidden_size
    );

    // Error checking
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        // Handle error silently in kernel launch
    }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"

// Helper function to validate tensor properties
void validate_tensors(const torch::Tensor& hidden_states, const torch::Tensor& weight) {
    TORCH_CHECK(hidden_states.device().is_cuda(), "hidden_states must be on CUDA device");
    TORCH_CHECK(weight.device().is_cuda(), "weight must be on CUDA device");
    TORCH_CHECK(hidden_states.is_contiguous(), "hidden_states must be contiguous");
    TORCH_CHECK(weight.is_contiguous(), "weight must be contiguous");
    TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16, 
                "hidden_states must be bfloat16, got " + hidden_states.dtype().str());
    TORCH_CHECK(weight.dtype() == torch::kBFloat16, 
                "weight must be bfloat16, got " + weight.dtype().str());
    TORCH_CHECK(hidden_states.dim() == 2, 
                "hidden_states must be 2D tensor, got " + std::to_string(hidden_states.dim()) + "D");
    TORCH_CHECK(weight.dim() == 1, 
                "weight must be 1D tensor, got " + std::to_string(weight.dim()) + "D");
    TORCH_CHECK(hidden_states.size(1) == 1536, 
                "hidden_states hidden dimension must be 1536, got " + std::to_string(hidden_states.size(1)));
    TORCH_CHECK(weight.size(0) == 1536, 
                "weight size must be 1536, got " + std::to_string(weight.size(0)));
    TORCH_CHECK(hidden_states.size(0) > 0, "batch_size must be positive");
}

// Main execution function
torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
    // Validate input tensors
    validate_tensors(hidden_states, weight);

    // Extract dimensions
    int batch_size = hidden_states.size(0);
    int hidden_size = hidden_states.size(1);

    // Create output tensor with same properties as input
    torch::Tensor output = torch::empty_like(hidden_states);

    // Get CUDA stream for async execution
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel with proper configuration
    rmsnorm_h1536_kernel_launch(
        hidden_states.data_ptr<__nv_bfloat16>(),
        weight.data_ptr<__nv_bfloat16>(),
        output.data_ptr<__nv_bfloat16>(),
        batch_size,
        hidden_size,
        stream
    );

    // Synchronize to ensure completion and check for errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        std::string error_msg = std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err);
        TORCH_CHECK(false, error_msg);
    }

    return output;
}

// Pybind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "RMSNorm kernel optimized for A800 GPU";

    // Bind the run function with proper documentation
    m.def("run", &run, 
          "Execute RMSNorm kernel on GPU",
          py::arg("hidden_states"),
          py::arg("weight"));

    // Add module-level constants
    m.attr("HIDDEN_SIZE") = 1536;
    m.attr("BLOCK_SIZE") = 256;
}
